using System.Collections.Generic;
using System.Xml;

public static class XmlConfigParser
{
    public static Dictionary<string, string> ParseConfig(string xmlFilePath)
    {
        Dictionary<string, string> settings = new Dictionary<string, string>();

        XmlDocument xmlDoc = new XmlDocument();
        xmlDoc.XmlResolver = new XmlUrlResolver();
        xmlDoc.Load(xmlFilePath);

        XmlNodeList nodes = xmlDoc.SelectNodes("/config/setting");

        foreach (XmlNode node in nodes)
        {
            settings.Add(node.Attributes["name"].Value, node.InnerText);
        }

        return settings;
    }
}